  const { WATCH_DIRECTORY } = require("../../../utils/constants");
  const { processAsFile } = require("../../../processLink/helpers");

  beforeEach(() => {
    fs.mkdirSync(WATCH_DIRECTORY, { recursive: true });
    jest.clearAllMocks();
  });

  afterEach(() => {
    for (const file of fs.readdirSync(WATCH_DIRECTORY)) {
      if (file === "__HOTDIR__.md") continue;
      fs.rmSync(path.join(WATCH_DIRECTORY, file), { force: true });
